package ingestion

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

const defaultDockerHubURL = "https://hub.docker.com"

// DockerHubSource polls Docker Hub for new image tags.
type DockerHubSource struct {
	client     *http.Client
	repository string
	baseURL    string
	sourceID   string
}

func NewDockerHubSource(client *http.Client, repository string, sourceID string) *DockerHubSource {
	return &DockerHubSource{
		client:     client,
		repository: repository,
		baseURL:    defaultDockerHubURL,
		sourceID:   sourceID,
	}
}

func (s *DockerHubSource) Name() string      { return "dockerhub" }
func (s *DockerHubSource) SourceID() string   { return s.sourceID }

func (s *DockerHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
	url := fmt.Sprintf("%s/v2/repositories/%s/tags/?page_size=25&ordering=last_updated",
		s.baseURL, s.repository)

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("fetch tags: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	var body struct {
		Results []struct {
			Name        string `json:"name"`
			LastUpdated string `json:"last_updated"`
		} `json:"results"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
		return nil, fmt.Errorf("decode response: %w", err)
	}

	results := make([]IngestionResult, 0, len(body.Results))
	for _, tag := range body.Results {
		ts, _ := time.Parse(time.RFC3339Nano, tag.LastUpdated)
		results = append(results, IngestionResult{
			Repository: s.repository,
			RawVersion: tag.Name,
			Timestamp:  ts,
		})
	}
	return results, nil
}

package ingestion

import (
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"io"
	"net/http"
	"strings"
	"time"
)

// GitHubWebhookHandler handles incoming GitHub release webhook events.
// It validates the HMAC signature, parses the release payload, and
// forwards results via the onResult callback.
type GitHubWebhookHandler struct {
	secret   string
	onResult func([]IngestionResult)
}

func NewGitHubWebhookHandler(secret string, onResult func([]IngestionResult)) *GitHubWebhookHandler {
	return &GitHubWebhookHandler{secret: secret, onResult: onResult}
}

func (h *GitHubWebhookHandler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "read body", http.StatusBadRequest)
		return
	}

	if !h.verifySignature(body, r.Header.Get("X-Hub-Signature-256")) {
		http.Error(w, "invalid signature", http.StatusForbidden)
		return
	}

	if r.Header.Get("X-GitHub-Event") != "release" {
		w.WriteHeader(http.StatusOK)
		return
	}

	var payload struct {
		Action  string `json:"action"`
		Release struct {
			TagName     string `json:"tag_name"`
			Body        string `json:"body"`
			PreRelease  bool   `json:"prerelease"`
			PublishedAt string `json:"published_at"`
		} `json:"release"`
		Repository struct {
			FullName string `json:"full_name"`
		} `json:"repository"`
	}
	if err := json.Unmarshal(body, &payload); err != nil {
		http.Error(w, "invalid json", http.StatusBadRequest)
		return
	}

	if payload.Action != "published" {
		w.WriteHeader(http.StatusOK)
		return
	}

	ts, _ := time.Parse(time.RFC3339, payload.Release.PublishedAt)
	result := IngestionResult{
		Repository: payload.Repository.FullName,
		RawVersion: payload.Release.TagName,
		Changelog:  payload.Release.Body,
		Timestamp:  ts,
	}

	h.onResult([]IngestionResult{result})
	w.WriteHeader(http.StatusOK)
}

func (h *GitHubWebhookHandler) verifySignature(body []byte, header string) bool {
	sig := strings.TrimPrefix(header, "sha256=")
	mac := hmac.New(sha256.New, []byte(h.secret))
	mac.Write(body)
	expected := hex.EncodeToString(mac.Sum(nil))
	return hmac.Equal([]byte(sig), []byte(expected))
}

package ingestion

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SourceLoader reads source configuration from the database and constructs
// IIngestionSource instances. It bridges the API-managed sources table with
// the polling orchestrator.
type SourceLoader struct {
	pool   *pgxpool.Pool
	client *http.Client
}

func NewSourceLoader(pool *pgxpool.Pool, client *http.Client) *SourceLoader {
	return &SourceLoader{pool: pool, client: client}
}

// LoadEnabledSources queries all enabled sources and constructs the
// appropriate IIngestionSource for each one based on provider.
func (l *SourceLoader) LoadEnabledSources(ctx context.Context) ([]IIngestionSource, error) {
	rows, err := l.pool.Query(ctx,
		`SELECT id, provider, repository FROM sources WHERE enabled = true`)
	if err != nil {
		return nil, fmt.Errorf("query enabled sources: %w", err)
	}
	defer rows.Close()

	var sources []IIngestionSource
	for rows.Next() {
		var id string
		var sourceType, repository string
		if err := rows.Scan(&id, &sourceType, &repository); err != nil {
			return nil, fmt.Errorf("scan source row: %w", err)
		}

		src := l.buildSource(id, sourceType, repository)
		if src == nil {
			slog.Warn("unsupported source type, skipping",
				"id", id, "type", sourceType, "repo", repository)
			continue
		}
		sources = append(sources, src)
	}
	return sources, rows.Err()
}

// LookupSourceID finds the source ID for a given (provider, repository) pair.
// Returns empty string and false if no matching enabled source exists.
func (l *SourceLoader) LookupSourceID(ctx context.Context, provider, repository string) (string, bool) {
	var id string
	err := l.pool.QueryRow(ctx,
		`SELECT id FROM sources WHERE provider = $1 AND repository = $2 AND enabled = true`,
		provider, repository,
	).Scan(&id)
	if err != nil {
		return "", false
	}
	return id, true
}

func (l *SourceLoader) buildSource(id string, sourceType, repository string) IIngestionSource {
	switch sourceType {
	case "dockerhub":
		return NewDockerHubSource(l.client, repository, id)
	default:
		return nil
	}
}

package main

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"time"

	"github.com/riverqueue/river"
	agentpkg "github.com/sentioxyz/releaseguard/internal/agent"
	"github.com/sentioxyz/releaseguard/internal/api"
	"github.com/sentioxyz/releaseguard/internal/db"
	"github.com/sentioxyz/releaseguard/internal/ingestion"
	"github.com/sentioxyz/releaseguard/internal/queue"
	"github.com/sentioxyz/releaseguard/internal/routing"
)

func main() {
	ctx, stop := signal.NotifyContext(context.Background(), os.Interrupt)
	defer stop()

	dbURL := envOr("DATABASE_URL", "postgres://localhost:5432/releaseguard?sslmode=disable")
	ghSecret := envOr("GITHUB_WEBHOOK_SECRET", "")
	addr := envOr("LISTEN_ADDR", ":8080")
	noAuth := os.Getenv("NO_AUTH") == "true"

	// Database
	pool, err := db.NewPool(ctx, dbURL)
	if err != nil {
		slog.Error("database connection failed", "err", err)
		os.Exit(1)
	}
	defer pool.Close()

	if err := db.RunMigrations(ctx, pool); err != nil {
		slog.Error("migrations failed", "err", err)
		os.Exit(1)
	}

	// API & routing store (created before River so we can register workers)
	// The river client is set to nil initially; TriggerAgentRun (which needs it)
	// won't be called until the server is up and the client is set below.
	pgStore := api.NewPgStore(pool, nil)

	// Register River workers
	workers := river.NewWorkers()
	notifyWorker := routing.NewNotifyWorker(pgStore)
	river.AddWorker(workers, notifyWorker)

	// Agent worker: requires GOOGLE_API_KEY. If unavailable, agent jobs
	// will remain in the queue until the key is configured and the server
	// is restarted.
	agentOrchestrator, err := agentpkg.NewOrchestrator(pgStore)
	if err != nil {
		slog.Warn("agent orchestrator not available — agent jobs will not be processed", "err", err)
	} else {
		agentWorker := agentpkg.NewAgentWorker(agentOrchestrator, pgStore)
		river.AddWorker(workers, agentWorker)
		slog.Info("agent worker registered")
	}

	riverClient, err := queue.NewRiverClient(pool, workers)
	if err != nil {
		slog.Error("river client failed", "err", err)
		os.Exit(1)
	}

	// Now that the river client exists, re-create pgStore with it so that
	// TriggerAgentRun can enqueue agent jobs.
	pgStore = api.NewPgStore(pool, riverClient)

	if err := riverClient.Start(ctx); err != nil {
		slog.Error("river start failed", "err", err)
		os.Exit(1)
	}

	// Ingestion layer
	ingestionStore := ingestion.NewPgStore(pool, riverClient)
	svc := ingestion.NewService(ingestionStore)

	loader := ingestion.NewSourceLoader(pool, http.DefaultClient)
	orch := ingestion.NewOrchestrator(svc, loader, 5*time.Minute)

	// GitHub webhook handler
	webhookHandler := ingestion.NewGitHubWebhookHandler(ghSecret, func(results []ingestion.IngestionResult) {
		for _, r := range results {
			sourceID, found := loader.LookupSourceID(ctx, "github", r.Repository)
			if !found {
				slog.Warn("github webhook: no matching source", "repo", r.Repository)
				continue
			}
			if err := svc.ProcessResults(ctx, sourceID, "github", []ingestion.IngestionResult{r}); err != nil {
				slog.Error("github webhook processing failed", "repo", r.Repository, "err", err)
			}
		}
	})
	broadcaster := api.NewBroadcaster()

	mux := http.NewServeMux()

	// Register webhook route
	mux.Handle("POST /webhook/github", webhookHandler)

	// Register all API v1 routes
	api.RegisterRoutes(mux, api.Dependencies{
		DB:                    pool,
		ProjectsStore:         pgStore,
		ReleasesStore:         pgStore,
		SubscriptionsStore:    pgStore,
		SourcesStore:          pgStore,
		ChannelsStore:         pgStore,
		ContextSourcesStore:   pgStore,
		SemanticReleasesStore: pgStore,
		AgentStore:            pgStore,
		KeyStore:              pgStore,
		HealthChecker:         pgStore,
		Broadcaster:           broadcaster,
		NoAuth:                noAuth,
	})

	srv := &http.Server{Addr: addr, Handler: api.CORS(mux)}

	// Start polling in background
	go orch.Run(ctx)

	// Start PostgreSQL LISTEN/NOTIFY → SSE bridge
	go api.ListenForNotifications(ctx, pool, broadcaster)

	// Start HTTP server
	go func() {
		slog.Info("server starting", "addr", srv.Addr)
		if err := srv.ListenAndServe(); err != http.ErrServerClosed {
			slog.Error("server error", "err", err)
		}
	}()

	<-ctx.Done()
	slog.Info("shutting down")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	riverClient.Stop(shutdownCtx)
	srv.Shutdown(shutdownCtx)
}

func envOr(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

