package ingestion

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"
)

const sampleAtomFeed = `<?xml version="1.0" encoding="UTF-8"?>
<feed xmlns="http://www.w3.org/2005/Atom">
  <title>Release notes from go-ethereum</title>
